package Full_Stack_ch3;

public class Alphabettriangle {

	public static void main(String[] args) {
		// TODO Auto-generated method stub

		 for(int i=1;i<=5;i++) {
	            char ch='A';
	            for(int j=1;j<=i;j++) {
	                System.out.print(ch+" ");
	                ch++;
	            }
	            System.out.println();
	        }
	}

}
